let nodeInspect;
/** @internal */
export function inspect(value, options) {
    nodeInspect ??= globalThis.process?.getBuiltinModule?.('node:util').inspect;
    /* v8 ignore else */
    if (nodeInspect) {
        return nodeInspect(value, options);
    }
    /* v8 ignore next */
    return JSON.stringify(value, null, 2);
}
